var body = $input.first().json.body || $input.first().json;
var tenantId = String(body.tenantId || '');
var documentType = String(body.documentType || '');
var documentId = String(body.documentId || '');

var UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!tenantId || !UUID_RE.test(tenantId)) {
  throw new Error('Tenant ID requis et doit être un UUID valide');
}
if (!documentId || !UUID_RE.test(documentId)) {
  throw new Error('Document ID requis et doit être un UUID valide');
}
if (!documentType) {
  throw new Error('Document Type requis');
}

return [{
  json: {
    tenantId: tenantId,
    documentType: documentType,
    documentId: documentId
  }
}];

var crypto = require('crypto');
var items = $input.all();
var chain = items.map(function(item) { return item.json; }).filter(function(r) { return r && r.id; });

if (chain.length === 0) {
  return [{json: {
    success: true,
    chain: [],
    integrityStatus: 'valid',
    message: 'Pas de piste d\'audit pour ce document'
  }}];
}

var parser = $('02. Parser').first().json;
var integrityValid = true;
var brokenAtIndex = -1;
var formattedChain = [];

var previousHash = '';

for (var i = 0; i < chain.length; i++) {
  var entry = chain[i];
  var dataToHash = previousHash + parser.documentType + parser.documentId + entry.etape + entry.date_etape;
  var calculatedHash = crypto.createHash('sha256').update(dataToHash).digest('hex');
  var hashMatches = calculatedHash === entry.hash_verification;

  formattedChain.push({
    id: entry.id,
    etape: entry.etape,
    etapePrecedente: entry.etape_precedente,
    etapeSuivante: entry.etape_suivante,
    dateEtape: entry.date_etape,
    utilisateur: entry.utilisateur,
    commentaire: entry.commentaire,
    hashVerification: entry.hash_verification,
    calculatedHash: calculatedHash,
    hashMatches: hashMatches,
    createdAt: entry.created_at
  });

  if (!hashMatches) {
    integrityValid = false;
    if (brokenAtIndex === -1) {
      brokenAtIndex = i;
    }
  }

  previousHash = entry.hash_verification;
}

return [{json: {
  success: true,
  chain: formattedChain,
  integrityStatus: integrityValid ? 'valid' : 'broken',
  brokenAtIndex: brokenAtIndex,
  totalEntries: chain.length
}}];
